content:
nal .prompt { color: var(--accent-green); }
  .terminal .cmd { color: var(--text-primary); }
  .terminal .output { color: var(--text-secondary); }
  .terminal .highlight-val { color: var(--accent-amber); }
  .terminal .comment { color: var(--text-muted); }
  .stat-box {
    background: var(--bg-card); border: 1px solid var(--border);
    border-radius: 16px; padding: 28px; text-align: center;
  }
  .insight-box {
    background: rgba(16, 185, 129, 0.08); border: 1px solid rgba(16, 185, 129, 0.25);
    border-radius: 16px; padding: 24px 28px; margin: 16px 0;
  }
  .insight-box p { font-size: 18px; font-weight: 500; color: var(--accent-green); line-height: 1.5; }
  .warning-box {
    background: rgba(245, 158, 11, 0.08); border: 1px solid rgba(245, 158, 11, 0.25);
    border-radius: 16px; padding: 24px 28px; margin: 16px 0;
  }
  .warning-box p { font-size: 18px; font-weight: 500; color: var(--accent-amber); line-height: 1.5; }

  .corvia-wm {
    font-family: 'Poppins', sans-serif;
    font-weight: 700;
    color: #E8C44E;
    letter-spacing: -1px;
  }

  .divider { height: 1px; background: var(--border); margin: 28px 0; }
  .flex-grow { flex: 1; }
  .cover-center { flex: 1; display: flex; flex-direction: column; justify-content: center; }
  .cover-tags { margin-top: 40px; display: flex; flex-wrap: wrap; gap: 12px; }
  .cover-tags .tag {
    display: inline-block; padding: 10px 20px; border-radius: 20px;
    font-size: 16px; font-weight: 600;
    background: rgba(59, 130, 246, 0.15); color: var(--accent-blue);
  }

  /* Bar chart */
  .bar-row {
    display: flex; align-items: center; gap: 16px; margin-bottom: 16px;
  }
  .bar-label {
    width: 180px; font-size: 17px; font-weight: 700; text-align: right;
    flex-shrink: 0;
  }
  .bar-track {
    flex: 1; height: 44px; background: var(--bg-card); border-radius: 10px;
    position: relative; overflow: hidden;
  }
  .bar-fill {
    height: 100%; border-radius: 10px;
    display: flex; align-items: center; justify-content: flex-end;
    padding-right: 16px; font-size: 16px; font-weight: 800;
    transition: width 0.3s ease;
  }
  .bar-value {
    font-size: 17px; font-weight: 800; min-width: 80px; text-align: left;
    margin-left: 12px; flex-shrink: 0;
  }
</style>
</head>
